item.content:encoded:
.site-logo img {
	max-width: 180px;
}

header, 
aside, 
header,
.site-title,
.site-description,
.main-navigation a {
	font-family: Georgia, "Times New Roman", Times, serif;
	font-size: 19px;
}

.site-header,
.widget-area {
	width: 170px;
}

@media only screen and (max-width: 1200px) {
	.site-header,
	.widget-area {
		width: 100%;
	}

}
